      {
        "title": "Ketersediaan Bahan",
        "content": "Ketersediaan bahan pembinaan adalah cabaran utama. Sesetengah bahan mungkin sukar didapati di kawasan tertentu, yang boleh melambatkan projek."
      },
      {
        "title": "Kualiti Bahan",
        "content": "Kualiti bahan mempengaruhi ketahanan dan kesesuaian untuk projek. Memastikan bahan berkualiti tinggi adalah penting untuk hasil yang baik."
      },
      {
        "title": "Kos Bahan",
        "content": "Kos bahan juga menjadi cabaran. Jumlah perbelanjaan untuk bahan pembinaan perlu dirancang dengan teliti agar projek tidak terjejas."
      }
    ]
  }
}
